const wiredscoreSubheaders = ["Digital-Connectivity And Coverage", "Digital Services"];

const CertificationsPage = () => {
  const renderItems = (section: (typeof specificationsData)[number], idx: number) => {
    if (idx !== 3) {
      return section.items.map((item, i) => (
        <li
          key={i}
          className="flex items-start text-white/90 text-[12px] md:text-[13px] lg:text-[13.5px] font-normal leading-snug"
          style={{ fontFamily: "'Nortica', sans-serif" }}
        >
          {item.svg}
          <span>{item.text}</span>
        </li>
      ));
    }

    const nodes: JSX.Element[] = [
      <li
        key="header-digital-resilience"
        className="text-white font-medium text-[12px] md:text-[13px] lg:text-[13.5px] mt-2 mb-1 first:mt-0"
        style={{ fontFamily: "'Nortica', sans-serif" }}
      >
        Digital Resilience
      </li>,
    ];

    section.items.forEach((item, i) => {
      const text = item.text.trim();
      if (wiredscoreSubheaders.includes(text)) {
        nodes.push(
          <li
            key={`header-${i}`}
            className="text-white font-medium text-[12px] md:text-[13px] lg:text-[13.5px] mt-3 mb-1"
            style={{ fontFamily: "'Nortica', sans-serif" }}
          >
            {text}
          </li>
        );
      } else {
        nodes.push(
          <li
            key={i}
            className="flex items-start gap-1.5 pl-1 text-white/80 text-[11px] md:text-[12px] lg:text-[12.5px] font-normal leading-snug"
            style={{ fontFamily: "'Nortica', sans-serif" }}
          >
            <span className="mt-[2px]">•</span>
            <span>{text}</span>
          </li>
        );
      }
    });

    return nodes;
  };

  return (
    <div className="w-full h-screen overflow-y-auto scrollbar-hide bg-[#0a2440] relative">
      {/* Diagonal line pattern background */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          backgroundImage:
            "repeating-linear-gradient(65deg, rgba(255,255,255,0.05) 0px, rgba(255,255,255,0.05) 1px, transparent 1px, transparent 34px)",
        }}
      />

      {/* Back Button */}
      <div className="fixed top-[60px] left-[20px] sm:top-10 sm:left-8 lg:top-auto lg:bottom-8 lg:left-8 z-50">
        <Link
          to="/media"
          className="block w-[32px] h-[32px] sm:w-[38px] sm:h-[38px] lg:w-[40px] lg:h-[40px] cursor-pointer hover:scale-105 transition-transform"
        >
          <img
            src={backImg}
            alt="Back"
            className="w-full h-full object-contain"
          />
        </Link>
      </div>

      {/* Content */}
      <div className="relative z-10 w-full min-h-screen flex flex-col font-sans px-5 sm:px-8 lg:px-10 pt-6 sm:pt-8 pb-16 lg:pb-8">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
          className="inline-flex items-center gap-2 mb-8 lg:mb-10 w-fit"
        >
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none" className="flex-shrink-0 text-white/50">
            <rect x="0" y="9" width="2.5" height="7" rx="1" fill="currentColor" />
            <rect x="4.5" y="6" width="2.5" height="10" rx="1" fill="currentColor" />
            <rect x="9" y="3" width="2.5" height="13" rx="1" fill="currentColor" />
            <rect x="13.5" y="0" width="2.5" height="16" rx="1" fill="currentColor" />
          </svg>
          <h1
            className="tracking-wide pb-2 border-b border-[#D9B77C]/50"
            style={{
              fontFamily: "'Nortica', sans-serif",
              fontSize: "clamp(18px, 2vw, 26px)",
              fontWeight: 500,
              color: "#D9B77C",
            }}
          >
            Our Certifications
          </h1>
        </motion.div>

        {/* Specifications Grid */}
        <div
          className="
            grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4
            gap-x-8 xl:gap-x-10
            gap-y-10 lg:gap-y-0
            flex-1
          "
        >
          {specificationsData.map((section, idx) => (
            <motion.div
              key={idx}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true, amount: 0.1 }}
              transition={{ duration: 0.6, ease: "easeOut", delay: (idx % 4) * 0.1 }}
              className="flex flex-col gap-2"
            >
              {/* Badge */}
              <img
                src={sectionBadges[idx]}
                alt={cleanTitle(section.title)}
                className="w-[64px] h-[64px] lg:w-[70px] lg:h-[70px] object-contain mb-2"
              />

              {/* Title */}
              <h2
                className="font-medium tracking-wide mb-1"
                style={{
                  fontFamily: "'Nortica', sans-serif",
                  fontSize: "clamp(14px, 1.2vw, 18px)",
                  color: "#D9B77C",
                }}
              >
                {cleanTitle(section.title)}
              </h2>

              {/* Items */}
              <ul className="flex flex-col gap-1.5">
                {renderItems(section, idx)}
              </ul>
            </motion.div>
          ))}
        </div>
      </div>

      <style>{`
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default CertificationsPage;